                for pat in patterns:
                    if re.search(pat, text_lower, flags=re.IGNORECASE):
                        found_completion = True
                        break
        if found_completion:
            break
    if found_completion:
        matched_projects.append({'Project_Name': rec['Project_Name_norm'], 'Amount': rec['Amount']})

